import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"TLS、证书与 HTTPS","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/linux-network/09-tls-certificates-https.md","filePath":"05-backend-data/notes/linux-network/09-tls-certificates-https.md","lastUpdated":1784255512000}'),n={name:"05-backend-data/notes/linux-network/09-tls-certificates-https.md"};function l(r,a,p,h,d,o){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="tls、证书与-https" tabindex="-1">TLS、证书与 HTTPS <a class="header-anchor" href="#tls、证书与-https" aria-label="Permalink to &quot;TLS、证书与 HTTPS&quot;">​</a></h1><p>TLS 为连接提供机密性、完整性和对端身份认证；X.509 证书把公钥与名称等身份声明绑定；HTTPS 是在 TLS 保护下传输 HTTP 语义。</p><h2 id="_1-tls-能保证什么" tabindex="-1">1. TLS 能保证什么 <a class="header-anchor" href="#_1-tls-能保证什么" aria-label="Permalink to &quot;1. TLS 能保证什么&quot;">​</a></h2><ul><li>机密性：没有会话密钥的路径观察者不能直接读取应用明文。</li><li>完整性：篡改受保护记录会被检测，连接失败而不是静默交付修改内容。</li><li>身份认证：客户端按信任链和期望主机名验证服务端；是否认证客户端取决于是否使用 mTLS。</li></ul><p>TLS 不证明应用无漏洞、不验证响应业务正确、不隐藏所有元数据，也不阻止已获应用权限的服务读取明文。IP、端口、流量大小与时序通常仍可见；TLS 1.3 的普通 SNI 也可被路径观察，除非使用并成功协商 ECH 等独立机制。</p><h2 id="_2-证书的关键字段" tabindex="-1">2. 证书的关键字段 <a class="header-anchor" href="#_2-证书的关键字段" aria-label="Permalink to &quot;2. 证书的关键字段&quot;">​</a></h2><p>X.509 证书是由 issuer 签名的结构化对象。实际验证关注：</p><table tabindex="0"><thead><tr><th>字段/扩展</th><th>作用</th><th>失败边界</th></tr></thead><tbody><tr><td>Subject</td><td>被签发实体信息</td><td>现代 TLS 主机名验证以 SAN 为准，不依赖 Common Name 回退</td></tr><tr><td>Issuer</td><td>签发者名称</td><td>名称相同不等于可信，仍需验证签名和链</td></tr><tr><td>Serial Number</td><td>issuer 范围内唯一标识</td><td>常用于吊销信息</td></tr><tr><td>Validity</td><td><code>notBefore</code> 到 <code>notAfter</code></td><td>本机时间错误、尚未生效、过期都会失败</td></tr><tr><td>Subject Alternative Name</td><td>允许的 DNS 名/IP 等身份</td><td>URL 用 DNS 名时匹配 dNSName；用 IP literal 时需 iPAddress SAN</td></tr><tr><td>Basic Constraints</td><td>是否 CA、path length</td><td>终端证书不能被当 CA 签发下级</td></tr><tr><td>Key Usage</td><td>密钥可做数字签名、证书签名等</td><td>与实际用途不符会失败</td></tr><tr><td>Extended Key Usage</td><td>serverAuth/clientAuth 等应用用途</td><td>服务端和客户端用途不可任意互换</td></tr><tr><td>Authority/Subject Key Identifier</td><td>帮助构建链</td><td>不是单独的信任证明</td></tr><tr><td>Signature Algorithm</td><td>issuer 对证书的签名算法</td><td>禁用算法或签名不匹配会失败</td></tr></tbody></table><p>通配符如 <code>*.example.com</code> 只匹配一个左侧 label，例如可匹配 <code>api.example.com</code>，不匹配 <code>a.b.example.com</code> 或裸 <code>example.com</code>。国际化域名按规范化后的 A-label 等规则处理，应用不要自行用字符串后缀代替证书验证库。</p><h2 id="_3-信任链与-trust-anchor" tabindex="-1">3. 信任链与 trust anchor <a class="header-anchor" href="#_3-信任链与-trust-anchor" aria-label="Permalink to &quot;3. 信任链与 trust anchor&quot;">​</a></h2><p>服务器通常发送 leaf 和必要 intermediate，不必发送 root。客户端从 leaf 校验签名、约束、用途和时间，构建到本地信任存储中的 trust anchor。客户端信任 root 是本地策略，不是因为服务器把 root 发来。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart BT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L[&quot;Leaf：api.example.com&quot;] --&gt;|&quot;由其签名&quot;| I[&quot;Intermediate CA&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt;|&quot;由其签名&quot;| R[&quot;Root CA / trust anchor&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[&quot;客户端信任存储&quot;] --&gt; R</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>服务器漏发 intermediate 时，有些客户端因历史缓存或 AIA 获取仍成功，干净客户端会失败；部署必须用不依赖偶然缓存的客户端验证完整链。交叉签名可能形成多条可构建路径，最终选择受客户端信任库和验证实现影响。</p><p>私有 CA 只有在客户端显式安装相应 trust anchor 后才可信。把私有 root 加入系统全局信任会影响整台机器，优先使用应用专用 trust store 并限制用途。</p><h2 id="_4-主机名验证" tabindex="-1">4. 主机名验证 <a class="header-anchor" href="#_4-主机名验证" aria-label="Permalink to &quot;4. 主机名验证&quot;">​</a></h2><p>连接 <code>https://api.example.com</code> 时，客户端验证证书是否授权 <code>api.example.com</code>。DNS 解析到哪个 IP 与证书名称验证是两个步骤：DNS 成功不表示证书匹配；用 <code>--resolve</code> 改 IP 仍保留 URL 主机名、SNI 和验证名。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resolve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.example.com:443:192.0.2.10</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --connect-timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://api.example.com/health</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>不要用 <code>https://192.0.2.10</code> 测试一个只含 DNS SAN 的证书，也不要通过 <code>curl -k</code>/<code>--insecure</code> 修复。<code>-k</code> 同时放弃关键身份认证，使中间人证书也可被接受。</p><h2 id="_5-tls-1-3-握手" tabindex="-1">5. TLS 1.3 握手 <a class="header-anchor" href="#_5-tls-1-3-握手" aria-label="Permalink to &quot;5. TLS 1.3 握手&quot;">​</a></h2><p>客户端发送 ClientHello，包括支持版本、cipher suites、key share、SNI、ALPN 等；服务端选择参数并返回 ServerHello，双方导出握手密钥；服务端发送加密的证书与 CertificateVerify、Finished；客户端验证后发送 Finished。TLS 1.3 密钥交换通常提供 forward secrecy。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant C as Client</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant S as Server</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;S: ClientHello（SNI、ALPN、key share）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S--&gt;&gt;C: ServerHello（选择版本与key share）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S--&gt;&gt;C: EncryptedExtensions、Certificate、CertificateVerify、Finished</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;C: 校验链、名称、时间、用途和签名</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;S: Finished</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;S: HTTP 请求</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>SNI 帮助一个 IP 上选择证书；ALPN 协商 <code>h2</code>、<code>http/1.1</code> 等应用协议。两者目的不同。TLS cipher suite 在 1.3 中主要选择 AEAD 与 hash，证书签名算法另行协商。</p><h2 id="_6-会话恢复与-0-rtt" tabindex="-1">6. 会话恢复与 0-RTT <a class="header-anchor" href="#_6-会话恢复与-0-rtt" aria-label="Permalink to &quot;6. 会话恢复与 0-RTT&quot;">​</a></h2><p>TLS 1.3 可用 PSK/session ticket 恢复，减少握手成本。0-RTT early data 可在握手完成前发送，但不具有普通握手同等级别的重放保护；网络中的攻击者可能让服务端重复接收 early data。</p><p>只有可安全重放、无副作用且服务端显式设计的操作才能接受 0-RTT。支付、创建订单、修改密码等不能仅凭 HTTP 方法名假设安全。服务端可拒绝 early data，客户端需能正常重发握手后的请求。</p><h2 id="_7-证书吊销的现实边界" tabindex="-1">7. 证书吊销的现实边界 <a class="header-anchor" href="#_7-证书吊销的现实边界" aria-label="Permalink to &quot;7. 证书吊销的现实边界&quot;">​</a></h2><p>证书可能在到期前因私钥泄漏或误签被撤销。CRL 发布列表；OCSP 查询单证书状态；OCSP stapling 允许服务器携带 CA 签名的状态响应，减少客户端查询隐私和可用性问题。</p><p>吊销检查不是所有 TLS 客户端都严格 hard-fail：网络不可达、隐私、性能和可用性使实现策略不同。短生命周期证书能缩短暴露窗口，但不能替代私钥保护、轮换和事件响应。必须以实际客户端栈验证吊销策略，不能在正文或监控中假设“已吊销必然所有连接立刻失败”。</p><h2 id="_8-openssl-验证" tabindex="-1">8. OpenSSL 验证 <a class="header-anchor" href="#_8-openssl-验证" aria-label="Permalink to &quot;8. OpenSSL 验证&quot;">​</a></h2><p>以下命令只读取公开握手信息，不发送应用凭据：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s_client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -servername</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -verify_hostname</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -verify_return_error</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -showcerts</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>重点检查最后 <code>Verification: OK</code>/verify return code、协商版本、cipher、ALPN、leaf SAN、有效期和服务器发送链。只看到 <code>CONNECTED</code> 不表示验证成功。<code>s_client</code> 是诊断工具，不等于浏览器完整策略。</p><p>保存 leaf 后可检查：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaf.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -subject</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -issuer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -serial</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dates</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ext</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subjectAltName</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -ext</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> basicConstraints</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ext</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keyUsage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ext</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> extendedKeyUsage</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>openssl verify -CAfile roots.pem -untrusted intermediates.pem -verify_hostname api.example.com leaf.pem</code> 用显式文件验证。不要把从不可信连接下载的 leaf/intermediate 临时加入 root trust 来“通过”。私钥永远不应交给 <code>x509</code> 检查或贴进日志。</p><h2 id="_9-时间与续期" tabindex="-1">9. 时间与续期 <a class="header-anchor" href="#_9-时间与续期" aria-label="Permalink to &quot;9. 时间与续期&quot;">​</a></h2><p>证书验证依赖客户端当前时间。NTP 故障、休眠恢复、虚拟机时钟漂移会造成“尚未生效/已过期”。监控至少覆盖 leaf 剩余有效期、自动续期任务结果、实际入口当前提供的 serial/fingerprint、各地域握手成功。</p><p>续期成功不代表服务已加载新证书。可能更新了磁盘文件但代理未 reload，或多实例只更新部分。验证应从客户端连接每个入口/实例确认实际 leaf，而不是只查看证书文件。</p><p>私钥权限应限制到 TLS 终止进程；更好的系统使用密钥服务/HSM 或不可导出密钥。轮换必须有旧新并存窗口、回滚、权限和部署验证。</p><h2 id="_10-mtls" tabindex="-1">10. mTLS <a class="header-anchor" href="#_10-mtls" aria-label="Permalink to &quot;10. mTLS&quot;">​</a></h2><p>mTLS 中服务端请求客户端证书并验证到受信 client CA，同时客户端仍验证服务端。证书身份应映射为明确授权主体；“证书有效”不自动有调用所有 API 的权限。</p><p>代理终止 mTLS 后向上游传递身份时，应用只能信任受控代理建立的、不可由外部直接注入的通道/header。若后端可被绕过直连，攻击者可伪造身份 header。需要网络隔离、header 清洗和已认证的代理—后端连接。</p><h2 id="_11-https-的边界" tabindex="-1">11. HTTPS 的边界 <a class="header-anchor" href="#_11-https-的边界" aria-label="Permalink to &quot;11. HTTPS 的边界&quot;">​</a></h2><p>HTTPS 保护 TLS 端点之间的数据。如果 TLS 在负载均衡器终止，负载均衡器可见明文；到后端可使用受控私网明文、重新加密或 mTLS，选择取决于威胁模型与运维成本。</p><p>混合内容、Cookie <code>Secure</code>、HSTS、CSP、认证与 CSRF 属于 Web 安全的其他层。HSTS 告诉浏览器在有效期内只用 HTTPS，并不修复无效证书；首次访问和预加载另有边界。</p><h2 id="_12-完整案例-部分客户端证书验证失败" tabindex="-1">12. 完整案例：部分客户端证书验证失败 <a class="header-anchor" href="#_12-完整案例-部分客户端证书验证失败" aria-label="Permalink to &quot;12. 完整案例：部分客户端证书验证失败&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>浏览器管理员机器正常，干净容器和部分移动客户端报 <code>unable to get local issuer certificate</code>。</li><li>leaf 主机名与时间有效。</li><li>服务器只发送 leaf，管理员机器曾访问同 CA 站点。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>用干净 trust 环境的 <code>openssl s_client -showcerts -verify_return_error</code> 重现。</li><li>检查服务端 Certificate 消息，确认缺少 intermediate。</li><li>独立取得 CA 发布的正确 intermediate，验证其 subject/issuer、Basic Constraints 和签名链。</li><li>配置服务端发送 leaf + intermediate，避免发送无关证书和把 root 当必需链。</li><li>reload 后从每个入口重新握手，比较实际 serial 与链。</li><li>同时用 <code>-verify_hostname</code> 测正确名称和故意错误名称。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>干净容器、移动客户端和浏览器都能构建到各自 trust anchor；正确主机名通过，错误主机名失败。续期监控同时检查链完整性与实际入口证书。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若链完整仍失败，按顺序检查客户端是否信任 root、时间、SAN、EKU、算法策略和代理是否替换证书。若公司代理使用私有 CA，只应在受控设备安装该 CA，不能要求公共客户端信任。不可用 <code>-k</code> 作为健康检查，因为它会把身份错误报告为成功。</p><h2 id="_13-常见错误" tabindex="-1">13. 常见错误 <a class="header-anchor" href="#_13-常见错误" aria-label="Permalink to &quot;13. 常见错误&quot;">​</a></h2><ul><li>把加密等同身份验证，或把有效证书等同应用授权。</li><li>只检查过期日期，不检查 SAN、用途、链和实际部署证书。</li><li>服务器漏发 intermediate，却因本机缓存成功而上线。</li><li>用 IP 访问 DNS 证书，再通过关闭验证“修复”。</li><li>认为吊销在所有客户端上都会立即 hard-fail。</li><li>对有副作用请求启用 0-RTT，却没有重放防护。</li><li>私钥放入镜像、命令行、日志或宽权限共享卷。</li></ul><h2 id="_14-练习与完成标准" tabindex="-1">14. 练习与完成标准 <a class="header-anchor" href="#_14-练习与完成标准" aria-label="Permalink to &quot;14. 练习与完成标准&quot;">​</a></h2><ol><li>对测试域名输出 leaf SAN、时间、EKU、链和 ALPN，解释每项失败表现。</li><li>用 <code>--resolve</code> 将域名指向测试 IP，验证正确域名与错误域名分支。</li><li>设计证书续期验收：文件更新、服务 reload、每入口实际 serial、链与剩余期。</li><li>完成标准：不关闭验证；能区分 DNS、TCP、TLS 链、主机名、时间、应用协议与授权失败。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc8446.html" target="_blank" rel="noreferrer">RFC 8446：TLS 1.3</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9525.html" target="_blank" rel="noreferrer">RFC 9525：Service Identity in TLS</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc5280.html" target="_blank" rel="noreferrer">RFC 5280：Internet X.509 PKI Certificate and CRL Profile</a>（访问日期：2026-07-17）</li><li><a href="https://docs.openssl.org/master/man1/openssl-s_client/" target="_blank" rel="noreferrer">OpenSSL s_client</a>（访问日期：2026-07-17）</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/Security/Transport_Layer_Security" target="_blank" rel="noreferrer">MDN：Transport Layer Security</a>（访问日期：2026-07-17）</li></ul>`,60)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
